import { app } from 'electron';
import fs from 'fs';
import path from 'path';

interface AppPreferencesData {
  maxDeploymentLogLines?: number;
}

const DEFAULT_PREFERENCES: AppPreferencesData = {
  maxDeploymentLogLines: 1000, // Default: store 1000 lines of logs
};

export class AppPreferences {
  private cache: AppPreferencesData | null = null;

  private get filePath(): string {
    const dir = app.getPath('userData');
    return path.join(dir, 'app-preferences.json');
  }

  private load(): AppPreferencesData {
    if (this.cache) {
      return this.cache;
    }

    try {
      const raw = fs.readFileSync(this.filePath, 'utf-8');
      const parsed = JSON.parse(raw) as AppPreferencesData;
      this.cache = {
        maxDeploymentLogLines: parsed.maxDeploymentLogLines ?? DEFAULT_PREFERENCES.maxDeploymentLogLines,
      };
    } catch {
      this.cache = { ...DEFAULT_PREFERENCES };
    }

    return this.cache!;
  }

  private persist(data: AppPreferencesData) {
    this.cache = data;
    try {
      fs.writeFileSync(this.filePath, JSON.stringify(data, null, 2), 'utf-8');
    } catch (error) {
      console.error('[AppPreferences] Failed to persist preferences:', error);
    }
  }

  getMaxDeploymentLogLines(): number {
    const data = this.load();
    return data.maxDeploymentLogLines ?? DEFAULT_PREFERENCES.maxDeploymentLogLines!;
  }

  setMaxDeploymentLogLines(lines: number) {
    // Validate range: 100-10000
    const validatedLines = Math.max(100, Math.min(10000, lines));

    const data = this.load();
    if (data.maxDeploymentLogLines === validatedLines) {
      return;
    }

    this.persist({
      ...data,
      maxDeploymentLogLines: validatedLines,
    });
  }

  getAll(): AppPreferencesData {
    return this.load();
  }
}

export const appPreferences = new AppPreferences();
